const RealtimeDashboard={channel: null,callbacks:{},isConnected: false,reconnectAttempts: 0,maxReconnectAttempts: 5,init(){const client=window.SupabaseAPI?.getClient();if(!client){return false;}this.channel=client.channel('dashboard-realtime').on('postgres_changes',{event: '*',schema: 'public',table: 'customers'},(payload)=>this.handleChange('customers',payload)).on('postgres_changes',{event: '*',schema: 'public',table: 'contacts'},(payload)=>this.handleChange('contacts',payload)).on('postgres_changes',{event: '*',schema: 'public',table: 'scheduled_posts'},(payload)=>this.handleChange('posts',payload)).on('postgres_changes',{event: '*',schema: 'public',table: 'invoices'},(payload)=>this.handleChange('invoices',payload)).on('postgres_changes',{event: '*',schema: 'public',table: 'deals'},(payload)=>this.handleChange('deals',payload)).subscribe((status)=>{this.handleConnectionStatus(status);});return true;},handleConnectionStatus(status){this.isConnected=status==='SUBSCRIBED';this.updateConnectionIndicator();if(status==='SUBSCRIBED'){this.reconnectAttempts=0;}else if(status==='CLOSED'||status==='CHANNEL_ERROR'){this.attemptReconnect();}},attemptReconnect(){if(this.reconnectAttempts>=this.maxReconnectAttempts){return;}this.reconnectAttempts++;const delay=Math.min(1000*Math.pow(2,this.reconnectAttempts),30000);setTimeout(()=>{this.disconnect();this.init();},delay);},handleChange(table,payload){if(window.DataSync){window.DataSync.handleRealtimeUpdate(table,payload);}this.showUpdateToast(table,payload.eventType);if(this.callbacks[table]){this.callbacks[table].forEach(cb=>cb(payload));}if(this.callbacks['*']){this.callbacks['*'].forEach(cb=>cb(table,payload));}},onTableChange(table,callback){if(!this.callbacks[table]){this.callbacks[table]=[];}this.callbacks[table].push(callback);return()=>{this.callbacks[table]=this.callbacks[table].filter(cb=>cb!==callback);};},showUpdateToast(table,eventType){const tableNames={customers: 'Khách hàng',contacts: 'Lead',posts: 'Bài viết',invoices: 'Hóa đơn',deals: 'Deals'};const eventNames={INSERT: 'mới được thêm',UPDATE: 'đã cập nhật',DELETE: 'đã xóa'};const message=`${tableNames[table]||table}${eventNames[eventType]||eventType}`;if(window.SadecToast){window.SadecToast.show(message,'info',3000);}},updateConnectionIndicator(){const indicator=document.querySelector('.realtime-indicator');if(indicator){indicator.classList.toggle('connected',this.isConnected);indicator.title=this.isConnected ? 'Realtime: Connected' : 'Realtime: Disconnected';}const statusBadge=document.querySelector('[data-realtime-status]');if(statusBadge){statusBadge.textContent=this.isConnected ? '🟢 Live' : '🔴 Offline';statusBadge.className=this.isConnected ? 'badge badge-success' : 'badge badge-error';}},disconnect(){if(this.channel){this.channel.unsubscribe();this.channel=null;this.isConnected=false;}},async refreshAll(){if(window.DataSync){await Promise.all([ window.DataSync.fetch('customers',{}),window.DataSync.fetch('leads',{}),window.DataSync.fetch('posts',{})]);}}};document.addEventListener('DOMContentLoaded',()=>{setTimeout(()=>{RealtimeDashboard.init();},1000);});window.RealtimeDashboard=RealtimeDashboard;